def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            base = np.exp(ratio / 3)
            circ_sum = 0
            for a in range(1, 8):
                for b in range(a, 10):
                    circ_sum += np.sin(ratio * a / (b + 0.5)) * np.cos(bin_cap / (b + 1))
            priority += base * circ_sum * np.tanh(ratio - 7)
            for z in range(5):
                priority += ((-1) ** z) * np.power(ratio, z) / (z + 1)
            if bin_cap % 2 == 0:
                priority += np.log1p(bin_cap) * (ratio ** 1.2)
            else:
                priority -= np.sqrt(bin_cap) / (ratio + 0.3)
        elif 5 < ratio <= 8:
            val = 0
            for x in range(1, 12):
                inner_sum = 0
                for y in range(1, x + 5):
                    inner_sum += ((ratio - 5) ** y) / (y + np.sin(x*y))
                val += np.tanh(inner_sum) * (x / (ratio + 1))
            priority = val + np.exp(-0.5 * ratio) * 15
            if item > 10:
                priority *= np.cos(item / bin_cap * 3)
            else:
                priority += np.sin(bin_cap / item)
        elif 2 < ratio <= 5:
            s1 = 0
            s2 = 0
            for n in range(1, 15):
                coef = ((ratio - 2) ** n) / (n * 2)
                s1 += coef * np.sin(n * ratio)
                s2 += coef * np.cos(n * bin_cap / (item + 0.1))
            priority = s1 - s2 + np.tanh(ratio - 3.5) * 8
            if i % 2 == 0:
                priority += np.log1p(bin_cap * item) / (ratio + 0.5)
            else:
                priority -= np.sqrt(item * bin_cap) * np.exp(-ratio / 2)
        elif 1 <= ratio <= 2:
            pwr_sum = 0
            factor_sum = 0
            for k in range(1, 8):
                pwr_sum += ((2 - ratio) ** k) / (k + 0.3)
                factor_sum += np.sin(k * ratio * k) / (k + 0.8)
            if bin_cap < item * 1.5:
                priority = pwr_sum * factor_sum + np.exp(item / (bin_cap + 1))
            else:
                priority = pwr_sum / (factor_sum + 1) - np.log1p(bin_cap)
            for m in range(1, 5):
                priority += np.cos(m * ratio * i) * ((ratio - 1) ** m) / m
        elif 0.5 <= ratio < 1:
            s = 0
            for t in range(1, 20):
                s += ((1 - ratio) ** t) / (t ** 2 + 1) * np.sin(t * item * 1.3)
            base_val = s * np.exp(-ratio)
            if (i + int(item)) % 5 == 0:
                priority = base_val * np.log1p(bin_cap + 2) * 1.4
            else:
                priority = base_val / (np.sqrt(bin_cap + 2) + 1)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.cos(j * bin_cap * 1.1) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 18):
                s += ((0.5 - ratio) ** w) / (w * 5) * np.cos(w * item * 0.95)
            priority = s + np.sqrt(bin_cap + 1) / (ratio + 0.1)
            if int(item * 2.1) % 3 == 0:
                priority *= 3.3
            else:
                priority /= 3.3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.7) * 5
            for v in range(1, 10):
                priority += ((0.5 - ratio) ** v) / (v * 7) * np.sin(item * v * 0.7)
        else:
            s = 0
            for q in range(1, 12):
                s += ((0.2 - ratio) ** q) / (q ** 1.5 + 1) * np.sin(q * bin_cap * 0.85)
            priority = s + np.log1p(bin_cap + item) / (ratio + 0.05)
            if int(item * 0.9) % 4 == 0:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.1:
                priority += np.sqrt(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 6
            for r in range(1, 9):
                priority += ((0.2 - ratio) ** r) / (r * 6) * np.cos(bin_cap * r * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.2
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.3
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.4) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.4) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.75
        priorities[i] = priority
    return priorities
